sys_script.script:
// Business Rule: Update Team XP on Profile XP Change
// Globals available: current, previous, gs, GlideRecord, GlideDateTime
(function executeRule(current, previous) {
    var userProfileSysId = current.getUniqueValue();

    // Find all teams this user belongs to
    var teamMemberGr = new GlideRecord('x_2063628_flowmi_0_fm_team_member');
    teamMemberGr.addQuery('user_profile', userProfileSysId);
    teamMemberGr.query();

    while (teamMemberGr.next()) {
        var teamSysId = teamMemberGr.getValue('team');

        // Recalculate team total_xp as sum of all member profiles
        var totalTeamXP = 0;
        var memberCount = 0;
        var membersGr = new GlideRecord('x_2063628_flowmi_0_fm_team_member');
        membersGr.addQuery('team', teamSysId);
        membersGr.query();

        while (membersGr.next()) {
            memberCount++;
            var memberProfileSysId = membersGr.getValue('user_profile');
            var memberProfile = new GlideRecord('x_2063628_flowmi_0_fm_user_profile');
            if (memberProfile.get(memberProfileSysId)) {
                totalTeamXP += parseInt(memberProfile.getValue('total_xp')) || 0;
            }
        }

        // Update team total_xp and member_count
        var team = new GlideRecord('x_2063628_flowmi_0_fm_team');
        if (team.get(teamSysId)) {
            team.setValue('total_xp', totalTeamXP);
            team.setValue('member_count', memberCount);
            team.update();
        }
    }

    gs.info('FlowMind: Updated team XP for user profile ' + userProfileSysId);
})(current, previous);
